import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../../services/api';
import { UploadCloud, X } from 'lucide-react';

const BASE_URL = 'http://localhost:5000';

const ProductEdit = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const isNew = id === 'new';
  const inputRef = useRef(null);

  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [oldPrice, setOldPrice] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('');
  const [tags, setTags] = useState('');
  const [stock, setStock] = useState('');
  const [featured, setFeatured] = useState(false);
  const [luxuryLabel, setLuxuryLabel] = useState('');
  const [existingImages, setExistingImages] = useState([]);
  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [loading, setLoading] = useState(!isNew);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!isNew) {
      const fetchProduct = async () => {
        try {
          const { data } = await api.get(`/products/${id}`);
          setName(data.name);
          setPrice(data.price);
          setOldPrice(data.oldPrice || '');
          setDescription(data.description);
          setCategory(data.category);
          setTags(data.tags?.join(', ') || '');
          setStock(data.stock);
          setFeatured(data.featured || false);
          setLuxuryLabel(data.luxuryLabel || '');
          setExistingImages(data.images || (data.imageUrl ? [data.imageUrl] : []));
        } catch (error) {
          console.error('Error fetching product:', error);
        } finally {
          setLoading(false);
        }
      };
      fetchProduct();
    }
  }, [id, isNew]);

  const handleFilesChange = (e) => {
    const selectedFiles = Array.from(e.target.files);
    setFiles(selectedFiles);
    const urls = selectedFiles.map(f => URL.createObjectURL(f));
    setPreviews(urls);
  };

  const clearFiles = () => {
    setFiles([]);
    setPreviews([]);
    if (inputRef.current) inputRef.current.value = '';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);

    const formData = new FormData();
    formData.append('name', name);
    formData.append('price', price);
    formData.append('oldPrice', oldPrice);
    formData.append('description', description);
    formData.append('category', category);
    formData.append('tags', tags);
    formData.append('stock', stock);
    formData.append('featured', featured);
    formData.append('luxuryLabel', luxuryLabel);
    files.forEach(file => formData.append('images', file));

    try {
      if (isNew) {
        await api.post('/products', formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
      } else {
        await api.put(`/products/${id}`, formData, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
      }
      navigate('/admin/products');
    } catch (error) {
      console.error('Error saving product:', error);
      alert('Error saving product');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div className="max-w-3xl">
      <h1 className="text-3xl font-serif font-bold mb-8">
        {isNew ? 'Create New Product' : 'Edit Product'}
      </h1>

      <form onSubmit={handleSubmit} className="bg-white p-6 rounded-lg border border-border shadow-sm space-y-6">
        <div>
          <label className="block text-sm font-medium mb-2">Product Name</label>
          <input type="text" value={name} onChange={(e) => setName(e.target.value)} required
            className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" />
        </div>

        <div className="grid grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-medium mb-2">Price ($)</label>
            <input type="number" value={price} onChange={(e) => setPrice(e.target.value)} required min="0" step="0.01"
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-2">Old Price ($)</label>
            <input type="number" value={oldPrice} onChange={(e) => setOldPrice(e.target.value)} min="0" step="0.01"
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" placeholder="Optional" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-2">Stock</label>
            <input type="number" value={stock} onChange={(e) => setStock(e.target.value)} required min="0"
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium mb-2">Description</label>
          <textarea value={description} onChange={(e) => setDescription(e.target.value)} required rows="5"
            className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors resize-y"></textarea>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-2">Category</label>
            <input type="text" value={category} onChange={(e) => setCategory(e.target.value)} required
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" placeholder="e.g. Outerwear" />
          </div>
          <div>
            <label className="block text-sm font-medium mb-2">Tags (comma separated)</label>
            <input type="text" value={tags} onChange={(e) => setTags(e.target.value)}
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" placeholder="luxury, cashmere, winter" />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-2">Luxury Label</label>
            <input type="text" value={luxuryLabel} onChange={(e) => setLuxuryLabel(e.target.value)}
              className="w-full p-3 border border-border rounded focus:outline-none focus:border-black transition-colors" placeholder="e.g. Handcrafted in Italy" />
          </div>
          <div className="flex items-end pb-1">
            <label className="flex items-center gap-3 cursor-pointer">
              <input type="checkbox" checked={featured} onChange={(e) => setFeatured(e.target.checked)} className="w-4 h-4 accent-black" />
              <span className="text-sm font-medium">Featured Product</span>
            </label>
          </div>
        </div>

        {/* Existing images */}
        {existingImages.length > 0 && previews.length === 0 && (
          <div>
            <label className="block text-sm font-medium mb-2">Current Images</label>
            <div className="flex gap-3 flex-wrap">
              {existingImages.map((img, i) => (
                <div key={i} className="w-24 h-24 rounded border border-border overflow-hidden bg-gray-light">
                  <img src={`${BASE_URL}${img}`} alt={`Product ${i + 1}`} className="w-full h-full object-cover" />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* New image upload */}
        <div>
          <label className="block text-sm font-medium mb-2">
            {existingImages.length > 0 ? 'Replace Images' : 'Product Images'}
          </label>
          {previews.length === 0 ? (
            <div
              className="border-2 border-dashed border-border rounded-lg p-10 text-center hover:border-gray-dark transition-colors cursor-pointer"
              onClick={() => inputRef.current.click()}
            >
              <input ref={inputRef} type="file" accept="image/*" multiple onChange={handleFilesChange} className="hidden" />
              <UploadCloud className="mx-auto h-12 w-12 text-gray-dark mb-4" />
              <p className="text-sm text-gray-dark mb-2"><span className="font-semibold text-black">Click to upload</span> product images</p>
              <p className="text-xs text-gray-dark">Select multiple images (max 10)</p>
            </div>
          ) : (
            <div>
              <div className="flex gap-3 flex-wrap mb-3">
                {previews.map((url, i) => (
                  <div key={i} className="w-24 h-24 rounded border border-border overflow-hidden bg-gray-light">
                    <img src={url} alt={`Preview ${i + 1}`} className="w-full h-full object-cover" />
                  </div>
                ))}
              </div>
              <button type="button" onClick={clearFiles} className="text-sm text-red-600 hover:text-red-800 flex items-center gap-1">
                <X size={14} /> Clear selected images
              </button>
            </div>
          )}
        </div>

        <div className="flex gap-4 pt-4 border-t border-border">
          <button type="submit" disabled={saving}
            className="bg-black text-white px-6 py-2 rounded hover:bg-gray-dark transition-colors disabled:opacity-50">
            {saving ? 'Saving...' : (isNew ? 'Create Product' : 'Update Product')}
          </button>
          <button type="button" onClick={() => navigate('/admin/products')}
            className="bg-white text-black border border-border px-6 py-2 rounded hover:bg-gray-light transition-colors">
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
};

export default ProductEdit;
